1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<[number, number]> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [0, -1],           [0, 1],
6	  [1, -1],  [1, 0],  [1, 1],
7	];
8	
9	const cellKey = (x: number, y: number): string => `${x},${y}`;
10	
11	const countLiveNeighbors = (
12	  x: number,
13	  y: number,
14	  liveSet: ReadonlySet<string>,
15	): number =>
16	  NEIGHBOR_OFFSETS.filter(([dx, dy]) => liveSet.has(cellKey(x + dx, y + dy)))
17	    .length;
18	
19	const survives = (neighborCount: number): boolean =>
20	  neighborCount === 2 || neighborCount === 3;
21	
22	export function nextGeneration(liveCells: Cell[]): Cell[] {
23	  const liveSet = new Set(liveCells.map(([x, y]) => cellKey(x, y)));
24	  return liveCells.filter(([x, y]) =>
25	    survives(countLiveNeighbors(x, y, liveSet)),
26	  );
27	}
