1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty array when given empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill live cells with only 1 neighbor (underpopulation)", () => {
12	    // Two adjacent live cells - each has only 1 neighbor, both die
13	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
14	  });
15	  it("should keep a live cell alive with 2 or 3 neighbors (survival)", () => {
16	    // 2x2 block: each cell has 3 neighbors → all survive
17	    const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]);
18	    expect(result).toContainEqual([0, 0]);
19	    expect(result).toContainEqual([1, 0]);
20	    expect(result).toContainEqual([0, 1]);
21	    expect(result).toContainEqual([1, 1]);
22	  });
23	  it("should kill a live cell with more than 3 neighbors (overpopulation)", () => {
24	    // Full 3x3 block; center (1,1) has 8 neighbors → dies
25	    const cells: [number, number][] = [
26	      [0, 0], [1, 0], [2, 0],
27	      [0, 1], [1, 1], [2, 1],
28	      [0, 2], [1, 2], [2, 2],
29	    ];
30	    const result = nextGeneration(cells);
31	    expect(result).not.toContainEqual([1, 1]);
32	  });
33	  it.todo("should birth a dead cell with exactly 3 live neighbors (reproduction)");
