const cellKey = (x: number, y: number): string => `${x},${y}`;

const isLiveAt = (liveSet: ReadonlySet<string>, x: number, y: number): boolean =>
  liveSet.has(cellKey(x, y));

const countLiveNeighbors = (
  x: number,
  y: number,
  liveSet: ReadonlySet<string>,
): number =>
  NEIGHBOR_OFFSETS.filter(([dx, dy]) => isLiveAt(liveSet, x + dx, y + dy))
    .length;
